/**
 * Tests whether the passed in trigger looks like an option. This
 * implementation first checks whether the passed in string starts with a
 * prefix that indicates an option. If this is the case, it is also checked
 * whether an option of this name is known for the current option. (This can
 * lead to reentrant invocations of this method, so care has to be taken
 * about this.)
 *
 * @param trigger the command line element to test
 * @return a flag whether this element seems to be an option
 */
public boolean looksLikeOption(final String trigger)
{
        // this is a reentrant call

        for (final Iterator i = prefixes.iterator(); i.hasNext();)
        {
            final String prefix = (String) i.next();

            if (trigger.startsWith(prefix))
            {
                // Check if this might be a negative number
                // If the part after the prefix is a valid number, it's likely a numeric value
                // rather than an option (e.g., "-42" is a number, not an option named "42")
                String remaining = trigger.substring(prefix.length());
                if (isNumeric(remaining)) {
                    // This looks like a number (e.g., "-42", "-3.14"), not an option
                    return false;
                }

                return true;
            }
        }
        return false;
}

/**
 * Checks if the given string is a valid number representation.
 * This includes integers, decimals, and scientific notation.
 * @param str the string to check
 * @return true if the string represents a valid number
 */
private boolean isNumeric(String str) {
    if (str == null || str.isEmpty()) {
        return false;
    }

    // Handle the special case of just "-" which is not a number
    if (str.equals("-")) {
        return false;
    }

    // Check for a valid number format
    try {
        Double.parseDouble(str);
        return true;
    } catch (NumberFormatException e) {
        return false;
    }
}

